# ============================================================
# GAM Evaluation Metrics — All 183 Species
#
#AI usage: the code below was debugged by Claude Sonnet 4.6. Code for plots was generated by it.
library(tidyverse)
library(ggplot2)
library(patchwork)
library(pROC)        

objs <- readRDS("imbalance_objects.rds") #from imbalance_analysis.R

gam_list     <- objs$gam_list     
pa_matrix    <- objs$pa_matrix     
prob_matrix  <- objs$prob_matrix   
species_list <- objs$species      
cwd_groups   <- objs$cwd_groups    

n_species <- length(species_list)
n_cwd     <- nrow(cwd_groups)

cat("Loaded", n_species, "GAMs and", n_cwd, "CWD groups.\n\n")




pb <- txtProgressBar(min = 0, max = n_species, style = 3)

metrics_list <- vector("list", n_species)

for (i in seq_along(species_list)) {

  sp      <- species_list[i]
  fit     <- gam_list[[sp]]
  s       <- summary(fit)

  # ── Observed and predicted vectors ─────────────────────────
  obs  <- pa_matrix[sp, ]          # observed 0/1 across 143 CWD groups
  pred <- prob_matrix[sp, ]        # GAM-predicted P(occurrence)

  # ── Basic counts ───────────────────────────────────────────
  n_pres <- sum(obs)
  prev   <- n_pres / n_cwd

  # ── GAM summary components ─────────────────────────────────
  edf      <- round(s$edf, 3)                     # EDF of s(CWD)
  p_smooth <- s$s.table[1, "p-value"]             # p-value for smooth
  dev_expl <- round(s$dev.expl * 100, 2)          # % deviance explained
  aic_val  <- round(AIC(fit), 3)

  # ── AUC-ROC ────────────────────────────────────────────────
  # Suppress pROC's direction message; direction = "<" because
  # higher predicted probability should correspond to presence (1).
  roc_obj <- suppressMessages(
    roc(response  = obs,
        predictor = pred,
        direction = "<",
        quiet     = TRUE)
  )
  auc_val <- round(as.numeric(auc(roc_obj)), 4)

  # ── Tjur's D ───────────────────────────────────────────────
  # Mean predicted prob at presences minus mean at absences.
  # Simple, well-calibrated pseudo-R² for binary models
  # (Tjur 2009, Scandinavian J. Statistics).
  tjur_d <- round(mean(pred[obs == 1]) - mean(pred[obs == 0]), 4)

  metrics_list[[i]] <- tibble(
    species           = sp,
    n_presences       = n_pres,
    prevalence        = round(prev, 4),
    edf               = edf,
    p_smooth          = p_smooth,
    p_smooth_sig      = case_when(          # significance stars for table
      p_smooth < 0.001 ~ "***",
      p_smooth < 0.01  ~ "**",
      p_smooth < 0.05  ~ "*",
      p_smooth < 0.1   ~ ".",
      TRUE             ~ "ns"
    ),
    deviance_explained = dev_expl,
    AIC                = aic_val,
    AUC                = auc_val,
    Tjur_D             = tjur_d
  )


}


metrics <- bind_rows(metrics_list)


metrics %>%
  dplyr::select(deviance_explained, AUC, Tjur_D, edf) %>%
  summary() %>%
  print()


#viz

# Colour scale anchored to n_presences (gives ecological context)
pres_colour <- scale_colour_viridis_c(name   = "No. CWD\ngroups\npresent",
                                      option = "plasma")

# AUC

fig1 <- ggplot(metrics, aes(x = AUC)) +
  geom_histogram(bins = 30, fill = "steelblue3",
                 colour = "white", alpha = 0.85) +
  geom_vline(xintercept = 0.7, linetype = "dashed",
             colour = "tomato3", linewidth = 0.8) +
  geom_vline(xintercept = 0.9, linetype = "dashed",
             colour = "darkgreen", linewidth = 0.8) +
  annotate("text", x = 0.70, y = Inf, vjust = 2, hjust = 1.05,
           label = "0.70", colour = "tomato3",  size = 3.5) +
  annotate("text", x = 0.90, y = Inf, vjust = 2, hjust = 1.05,
           label = "0.90", colour = "darkgreen", size = 3.5) +
  labs(
    title    = "Distribution of AUC values across 183 species",
    subtitle = "Dashed lines: conventional thresholds (0.70 = acceptable, 0.90 = excellent)",
    x        = "AUC-ROC",
    y        = "Number of species"
  ) +
  theme_bw(base_size = 12)


# % deviance explained

fig2 <- ggplot(metrics, aes(x = deviance_explained)) +
  geom_histogram(bins = 30, fill = "steelblue3",
                 colour = "white", alpha = 0.85) +
  geom_vline(xintercept = median(metrics$deviance_explained),
             linetype = "dashed", colour = "tomato3", linewidth = 0.8) +
  annotate("text",
           x     = median(metrics$deviance_explained) + 0.5,
           y     = Inf, vjust = 2, hjust = 0,
           label = paste0("median = ",
                          round(median(metrics$deviance_explained), 1), "%"),
           colour = "tomato3", size = 3.5) +
  labs(
    title = "Distribution of deviance explained across 183 species",
    x     = "Deviance explained (%)",
    y     = "Number of species"
  ) +
  theme_bw(base_size = 12)




print(fig1)
print(fig2)




write.csv(metrics, "gam_evaluation_metrics.csv", row.names = FALSE)

cat("  gam_evaluation_metrics.csv")






# AUC and deviance explained

plot_dat <- metrics %>%
  transmute(
    `AUC`                      = AUC,
    `Deviance explained` = deviance_explained / 100
  ) %>%
  pivot_longer(everything(), names_to = "metric", values_to = "value") %>%
  mutate(metric = factor(metric,
                         levels = c("AUC",
                                    "Deviance explained")))

summary_dat <- plot_dat %>%
  group_by(metric) %>%
  summarise(median_val = median(value, na.rm = TRUE), .groups = "drop")

ggplot(plot_dat, aes(x = metric, y = value, fill = metric)) +
  geom_boxplot(width = 0.45, outlier.shape = 21, outlier.size = 1.8,
               outlier.alpha = 0.7, linewidth = 0.6) +
  geom_jitter(width = 0.12, size = 1.4, alpha = 0.35, colour = "grey30") +
 

  scale_fill_manual(
    values = c("AUC"                      = "steelblue2",
               "Deviance explained" = "mediumpurple3"),
    guide  = "none"
  ) +
  scale_y_continuous(
    limits = c(0, 1.05),
    breaks = seq(0, 1, 0.1)
  ) +
  coord_cartesian(clip = "off") +
  labs(
    title    = "GAM model evaluation across 183 species",
    subtitle = ,
    x        = NULL,
    y        = NULL
  ) +
  theme_bw(base_size = 13) +
  theme(
    plot.subtitle    = element_text(size = 9, colour = "grey40"),
    axis.text.x      = element_text(size = 11, lineheight = 1.3),
    axis.text.y      = element_text(size = 9),
    panel.grid.minor = element_blank(),
    plot.margin      = margin(10, 80, 10, 10)
  )

